/// EXACT-match arm of `copy_kind_is_explicit_no_heap_move`: kinds that are
/// a provable no-incref pure move of operand 0 (bare `copy`, the named SSA/
/// var moves, the validate-and-pass-through guards). A bare `Copy` with no
/// `_original_kind` is handled by the caller (it is also a no-heap move).
#[inline]
pub fn copy_kind_is_explicit_no_heap_move_table(kind: &str) -> bool {
    matches!(
        kind,
        "copy"
            | "copy_var"
            | "guard_tag"
            | "guard_type"
            | "identity_alias"
            | "load_var"
            | "store_var"
    )
}

