/// Operand-independent result type facts for opcodes whose single result
/// type is intrinsic to the opcode. Operand-, attr-, and builtin-dependent
/// opcodes deliberately return None and are inferred by type_refine.rs.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum OperandIndependentResultType {
    I64,
    F64,
    Bool,
    Str,
    None,
    Bytes,
    DynBox,
    ListDynBox,
    DictDynBoxDynBox,
    SetDynBox,
}

impl OperandIndependentResultType {
    #[inline]
    pub fn to_tir_type(self) -> TirType {
        match self {
            OperandIndependentResultType::I64 => TirType::I64,
            OperandIndependentResultType::F64 => TirType::F64,
            OperandIndependentResultType::Bool => TirType::Bool,
            OperandIndependentResultType::Str => TirType::Str,
            OperandIndependentResultType::None => TirType::None,
            OperandIndependentResultType::Bytes => TirType::Bytes,
            OperandIndependentResultType::DynBox => TirType::DynBox,
            OperandIndependentResultType::ListDynBox => TirType::List(Box::new(TirType::DynBox)),
            OperandIndependentResultType::DictDynBoxDynBox => {
                TirType::Dict(Box::new(TirType::DynBox), Box::new(TirType::DynBox))
            }
            OperandIndependentResultType::SetDynBox => TirType::Set(Box::new(TirType::DynBox)),
        }
    }
}

