/// GVN numbering role by opcode. `Always` joins the scoped dominator
/// value table directly; `TypeGated` requires primitive operand proof at
/// the use site; `ValueKeyedConstant` receives same-block local value
/// numbers only; `Never` is not numbered. EXHAUSTIVE over OpCode.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum GvnNumberingRole {
    Never,
    Always,
    TypeGated,
    ValueKeyedConstant,
}

impl GvnNumberingRole {
    #[inline]
    pub fn is_value_keyed_constant(self) -> bool {
        matches!(self, GvnNumberingRole::ValueKeyedConstant)
    }
}

/// GVN numbering role by opcode. EXHAUSTIVE over OpCode so a new opcode
/// cannot silently enter or skip value numbering through a pass-local
/// wildcard/default.
