/// Result-side selected-alias ownership fact. These opcodes return one
/// borrowed operand's bits as their result, so backend lowering must
/// retain the selected object when an owned boxed result is produced.
/// Raw scalar lanes remain refcount-free. The table is keyed by explicit
/// `result_mints_owned_selected_operand` rows in op_kinds.toml.
#[inline]
pub fn opcode_result_mints_owned_selected_operand_table(opcode: OpCode) -> bool {
    matches!(opcode, OpCode::And | OpCode::Or)
}

/// Same selected-alias result ownership fact keyed by SimpleIR kind spelling.
/// String-dispatch backends must query this rather than duplicating an
/// `and`/`or` list by hand.
#[inline]
pub fn kind_result_mints_owned_selected_operand_table(kind: &str) -> bool {
    kind_to_opcode_table(kind).is_some_and(opcode_result_mints_owned_selected_operand_table)
}

/// Result-side ownership-transfer fact for Copy-lifted SimpleIR spellings.
/// These spellings intentionally remain outside `[[kind]]` so backconversion
/// and backend dispatch preserve their public wire names while still sharing
/// the finalizer/escape ownership fact with first-class Build* opcodes.
#[inline]
pub fn kind_result_absorbs_operand_ownership_table(kind: &str) -> bool {
    matches!(
        kind,
        "class_def" | "dict_new" | "frozenset_new" | "list_new" | "set_new" | "tuple_new"
    )
}

/// Per-SPELLING result finalizer-source facts. These Copy-lifted
/// extraction spellings return a fresh owned result whose finalizer
/// sensitivity is inherited from one source operand, but whose own
/// temporary ref should release at the statement unless Python-bound.
#[inline]
pub fn kind_result_finalizer_source_operand_table(kind: &str, _arity: usize) -> Option<usize> {
    match kind {
        "list_pop" => Some(0),
        _ => None,
    }
}

/// Result-validity fact for op results whose bits are not valid on every
/// outgoing edge. `ConditionalValidOnlyOnEdge` is the §2.8
/// `IterNextUnboxed` value-out: result 0 is initialized only on the
/// not-done edge and must never be dropped or retained from the exhaustion
/// edge. EXHAUSTIVE over OpCode; result indices not listed for an opcode
/// are unconditionally valid.
#[derive(Clone, Copy, PartialEq, Eq, Debug)]
pub enum ResultValidity {
    AlwaysValid,
    ConditionalValidOnlyOnEdge,
}

